-- Program: Extreme Shred
-- Category: Fat Loss -> fat_loss
-- Priority: High
-- Durations: [4, 6], Sessions: [6]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Extreme Shred',
    'High-intensity 6-day fat burning with AM cardio and PM strength to maximize calorie burn',
    'fat_loss',
    'advanced',
    6,
    6,
    'custom',
    ARRAY['Increase maximal strength', 'Progressive overload', 'Maximize calorie burn', 'Preserve lean muscle', 'Build cardiovascular endurance']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Extreme Shred - 4w 6x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Hard',
    4,
    'Extreme Shred - 4w 6x/wk',
    'fat_loss',
    6,
    60,
    ARRAY['Increase maximal strength', 'Progressive overload', 'Maximize calorie burn', 'Preserve lean muscle', 'Build cardiovascular endurance']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Extreme Shred'
ON CONFLICT DO NOTHING;

